type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (values: number[], min: number, max: number): number[] =>
  values.filter((v) => v >= min && v <= max);

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangeOrWild, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    const [start, end] =
      rangeOrWild === "*"
        ? [min, max]
        : rangeOrWild.includes("-")
          ? rangeOrWild.split("-").map(Number)
          : [parseInt(rangeOrWild, 10), max];

    if (isNaN(start) || isNaN(end) || start > end)
      throw new Error(`Invalid step range: ${rangeOrWild}`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return clamp(result, min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end)
      throw new Error(`Invalid range: ${segment}`);
    return clamp(range(start, end), min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  return [value];
};

const parseField = (expr: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  const segments = expr.split(",");
  const values = segments.flatMap((seg) => parseSegment(seg.trim(), min, max));

  const unique = [...new Set(values)].sort((a, b) => a - b);
  if (unique.length === 0)
    throw new Error(`No valid values for field "${field}": ${expr}`);

  return unique;
};

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );

  const fields: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  return fields.reduce(
    (acc, field, i) => ({ ...acc, [field]: parseField(parts[i], field) }),
    {} as ParsedCron
  );
}

