export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = { min: number; max: number };

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  const clamp = (n: number): number => {
    if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
    return n;
  };

  // Comma-separated list — recurse on each segment and deduplicate
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((segment) => parseField(segment.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step: */N or start-end/N
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepPart}`);

    if (rangePart === "*") {
      return rangeArray(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = clamp(parseInt(startStr, 10));
      const end   = clamp(parseInt(endStr,   10));
      if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
      return rangeArray(start, end, step);
    }

    const start = clamp(parseInt(rangePart, 10));
    return rangeArray(start, max, step);
  }

  // Wildcard
  if (expr === "*") {
    return rangeArray(min, max);
  }

  // Range: N-M
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = clamp(parseInt(startStr, 10));
    const end   = clamp(parseInt(endStr,   10));
    if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
    return rangeArray(start, end);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field value: "${expr}"`);
  return [clamp(n)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS.minute),
    hour:       parseField(hourExpr,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthExpr,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS.dayOfWeek),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, min: number, max: number): number[] {
  const all = range(min, max);

  // Wildcard
  if (expr === "*") return all;

  // Step: */n or range/n
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

    let candidates: number[];
    if (base === "*") {
      candidates = all;
    } else if (base.includes("-")) {
      const [lo, hi] = base.split("-").map(Number);
      candidates = range(clamp(lo, min, max), clamp(hi, min, max));
    } else {
      const start = parseInt(base, 10);
      candidates = range(clamp(start, min, max), max);
    }
    return candidates.filter((_, i) => i % step === 0);
  }

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").map((v) => {
      const n = parseInt(v.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value in list: ${v}`);
      return clamp(n, min, max);
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range: n-m
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${expr}`);
    return range(clamp(lo, min, max), clamp(hi, min, max));
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field value: ${expr}`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as Array<keyof CronFields>;
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return fields.reduce((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(exprs[i], min, max);
    return acc;
  }, {} as CronFields);
}

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 6 },
};

