};

function range(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, fieldMin: number, fieldMax: number): number[] {
  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    let start = fieldMin;
    let end = fieldMax;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }
    return range(start, end, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${segment}`);
    }
    return range(start, end);
  }

  // Wildcard
  if (segment === "*") {
    return range(fieldMin, fieldMax);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) {
    throw new Error(`Invalid value: ${segment}`);
  }
  return [val];
}

function parseField(expression: string, fieldMin: number, fieldMax: number): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const nums = parseSegment(part.trim(), fieldMin, fieldMax);
    for (const n of nums) {
      if (n < fieldMin || n > fieldMax) {
        throw new Error(`Value ${n} is out of range [${fieldMin}, ${fieldMax}]`);
      }
      values.add(n);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourExpr,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domExpr,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthExpr,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowExpr,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

