      if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min}-${max}]`);
      return n;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field value: ${segment}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min}-${max}]`);
  return [n];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronResult;

  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const { min, max } = FIELD_RANGES[field];

    // dayOfWeek: treat 7 as 0 (both are Sunday)
    if (field === "dayOfWeek") {
      let values = parseSegment(parts[i], min, max);
      values = values.map((v) => (v === 7 ? 0 : v));
      result[field] = [...new Set(values)].sort((a, b) => a - b);
    } else {
      result[field] = parseSegment(parts[i], min, max);
    }
  }

  return result;
}

