    return (isPlainObject(source) ? { ...source } : source ?? target) as T & S;
  }

  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
