interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseField(field: string, range: FieldRange): number[] {
  const { min, max } = range;

  // Comma-separated list
  if (field.includes(",")) {
    return [...new Set(
      field.split(",").flatMap((part) => parseField(part.trim(), range))
    )].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or start/n
  if (field.includes("/")) {
    const [base, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${field}`);
    }
    const start = base === "*" ? min : parseInt(base, 10);
    if (isNaN(start) || start < min || start > max) {
      throw new Error(`Invalid step start value: ${field}`);
    }
    const values: number[] = [];
    for (let i = start; i <= max; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range ${field} out of bounds [${min}-${max}]`);
    }
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }
  return [value];
}

export default function parseCron(expression: string): CronExpression {
