  }

  const fields = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  return fields.reduce((acc, field, index) => {
    acc[field] = parseField(parts[index], FIELD_RANGES[field]);
    return acc;
  }, {} as CronExpression);
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function expandRange(start: number, end: number, step: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const validate = (n: number): number => {
    if (n < min || n > max) {
      throw new RangeError(
        `Value ${n} out of range [${min}-${max}] for field "${field}"`
      );
    }
    return n;
  };

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    if (rangePart === "*") {
      return expandRange(min, max, step);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = validate(parseInt(startStr, 10));
      const end   = validate(parseInt(endStr,   10));
      if (start > end) throw new RangeError(`Invalid range "${rangePart}"`);
      return expandRange(start, end, step);
    }
    const start = validate(parseInt(rangePart, 10));
    return expandRange(start, max, step);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max, 1);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = validate(parseInt(startStr, 10));
    const end   = validate(parseInt(endStr,   10));
    if (start > end) throw new RangeError(`Invalid range "${expr}"`);
    return expandRange(start, end, 1);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid cron token "${expr}"`);
  return [validate(n)];
}

export default function parseCron(expression: string): CronResult {
