    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  const result = {} as CronResult;
  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(parts[i], fields[i]);
  }

