  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range "${segment}"`);
    const start = validateValue(parseInt(parts[0], 10), field);
    const end = validateValue(parseInt(parts[1], 10), field);
    if (start > end) throw new RangeError(`Invalid range "${segment}"`);
    return range(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new SyntaxError(`Invalid value "${segment}"`);
  return [validateValue(num, field)];
