function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function clamp(value: number, min: number, max: number, context: string): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${context}"`);
  }
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value in "${segment}"`);

    let from: number;
    let to: number;

    if (base === "*") {
      from = min;
      to = max;
    } else if (base.includes("-")) {
      const [a, b] = base.split("-").map(Number);
      from = clamp(a, min, max, field);
      to = clamp(b, min, max, field);
    } else {
      from = clamp(parseInt(base, 10), min, max, field);
      to = max;
    }

    const values: number[] = [];
    for (let v = from; v <= to; v += step) values.push(v);
    return values;
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range expression: "${segment}"`);
    const from = clamp(parseInt(parts[0], 10), min, max, field);
    const to = clamp(parseInt(parts[1], 10), min, max, field);
    return range(from, to);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${segment}" for field "${field}"`);
  return [clamp(num, min, max, field)];
}

function parseField(expression: string, field: CronField): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${field}": "${expression}"`);
    for (const v of parseSegment(trimmed, field)) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

