function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function expandRange(start: number, end: number, step: number, min: number, max: number, expr: string): number[] {
  if (isNaN(start) || isNaN(end) || isNaN(step)) throw new SyntaxError(`Invalid expression: "${expr}"`);
  if (step <= 0) throw new RangeError(`Step must be positive in "${expr}"`);
  assertInRange(start, min, max, expr);
  assertInRange(end,   min, max, expr);
  if (start > end) throw new RangeError(`Start ${start} exceeds end ${end} in "${expr}"`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseSegment(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n, start/n, start-end/n
  if (expr.includes("/")) {
    const slashIdx = expr.lastIndexOf("/");
    const step = parseInt(expr.slice(slashIdx + 1), 10);
    const rangePart = expr.slice(0, slashIdx);

    if (rangePart === "*") {
      return expandRange(min, max, step, min, max, expr);
    }
    if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      return expandRange(s, e, step, min, max, expr);
    }
    const start = parseInt(rangePart, 10);
    return expandRange(start, max, step, min, max, expr);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max, 1, min, max, expr);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [s, e] = expr.split("-").map(Number);
    return expandRange(s, e, 1, min, max, expr);
  }

  // Single value
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron token: "${expr}"`);
  assertInRange(value, min, max, expr);
  return [value];
}

function parseField(expr: string, field: CronField): number[] {
  const raw = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), field));
  return [...new Set(raw)].sort((a, b) => a - b);
}

