    return values;
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [loStr, hiStr] = expr.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max);
    const hi = clamp(parseInt(hiStr, 10), min, max);
    if (lo > hi) throw new RangeError(`Invalid range "${expr}"`);
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid cron field value "${expr}"`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
