export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_DEFS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(values: number[], min: number, max: number, field: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

function parseSegment(expr: string, min: number, max: number, field: string): number[] {
  // Comma-separated list — split and recurse
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap(part => parseSegment(part.trim(), min, max, field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step expression: */n or start-end/n or start/n
  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const rangeExpr = expr.slice(0, slashIdx);
    const stepStr = expr.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (!Number.isInteger(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start = min;
    let end = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [s, e] = rangeExpr.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangeExpr, 10);
      }
    }

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid step expression "${expr}" in field "${field}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return assertInRange(values, min, max, field);
  }

  // Wildcard
  if (expr === "*") {
    return rangeArray(min, max);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range "${expr}" in field "${field}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${expr}" in field "${field}"`);
    }
    return assertInRange(rangeArray(start, end), min, max, field);
  }

  // Single value
  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid token "${expr}" in field "${field}"`);
  }
  return assertInRange([num], min, max, field);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = FIELD_DEFS.map(
    ({ name, min, max }, i) => parseSegment(fields[i], min, max, name)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type CronField = {
  min: number;
  max: number;
};

const FIELDS: [keyof CronResult, CronField][] = [
  ["minute", { min: 0, max: 59 }],
  ["hour", { min: 0, max: 23 }],
  ["dayOfMonth", { min: 1, max: 31 }],
  ["month", { min: 1, max: 12 }],
  ["dayOfWeek", { min: 0, max: 6 }],
];

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(token: string, { min, max }: CronField): number[] {
  const results = new Set<number>();

  for (const part of token.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+)|(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[5], 10);
      if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);

      let start: number;
      let end: number;

      if (stepMatch[1] === "*") {
        start = min;
        end = max;
      } else if (stepMatch[2] !== undefined) {
        start = clamp(parseInt(stepMatch[2], 10), min, max);
        end = clamp(parseInt(stepMatch[3], 10), min, max);
        if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
      } else {
        start = clamp(parseInt(stepMatch[4], 10), min, max);
        end = max;
      }

      for (let i = start; i <= end; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = clamp(parseInt(rangeMatch[1], 10), min, max);
      const end = clamp(parseInt(rangeMatch[2], 10), min, max);
      if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      results.add(clamp(parseInt(numMatch[1], 10), min, max));
      continue;
    }

    throw new SyntaxError(`Unrecognized cron field token: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELDS.length; i++) {
    const [key, field] = FIELDS[i];
    result[key] = parseField(tokens[i], field);
  }

  return result;
}

