}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandField(expr: string, min: number, max: number): number[] {
  const all = () => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr === "*") return all();

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);
    return all().filter((v) => (v - min) % step === 0);
  }

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => expandField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.includes("-")) {
    const [startStr, rest] = expr.split("-");
    if (rest.includes("/")) {
      const [endStr, stepStr] = rest.split("/");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      const step = parseInt(stepStr, 10);
      if (isNaN(start) || isNaN(end) || isNaN(step) || step <= 0)
        throw new Error(`Invalid range with step: ${expr}`);
      if (start < min || end > max || start > end)
        throw new Error(`Range out of bounds: ${expr} (valid: ${min}-${max})`);
      const result: number[] = [];
      for (let i = start; i <= end; i += step) result.push(i);
      return result;
    }
    const start = parseInt(startStr, 10);
    const end = parseInt(rest, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${expr}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${expr} (valid: ${min}-${max})`);
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value: ${expr}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of bounds (valid: ${min}-${max})`);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = expandField(fields[i], min, max);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    if (part.includes("/")) {
      const slashIdx = part.indexOf("/");
      const rangePart = part.slice(0, slashIdx);
      const step = parseInt(part.slice(slashIdx + 1), 10);

      if (isNaN(step) || step <= 0) {
        throw new RangeError(`Invalid step in "${part}"`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map(Number);
          if (isNaN(lo) || isNaN(hi)) throw new TypeError(`Invalid range in "${part}"`);
          rangeMin = lo;
          rangeMax = hi;
        } else {
          rangeMin = parseInt(rangePart, 10);
          if (isNaN(rangeMin)) throw new TypeError(`Invalid value in "${part}"`);
        }
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new RangeError(`Range out of bounds in "${part}" (valid: ${min}–${max})`);
      }

      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    if (part.includes("-")) {
      const dashIdx = part.indexOf("-");
      const lo = parseInt(part.slice(0, dashIdx), 10);
      const hi = parseInt(part.slice(dashIdx + 1), 10);

      if (isNaN(lo) || isNaN(hi)) throw new TypeError(`Invalid range "${part}"`);
      if (lo < min || hi > max || lo > hi) {
        throw new RangeError(`Range "${part}" out of bounds (valid: ${min}–${max})`);
      }

      for (let i = lo; i <= hi; i++) values.add(i);
      continue;
    }

    const num = parseInt(part, 10);
    if (isNaN(num)) throw new TypeError(`Invalid token "${part}"`);
    if (num < min || num > max) {
      throw new RangeError(`Value ${num} out of bounds (valid: ${min}–${max})`);
    }
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length} — "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, ...FIELD_RANGES.minute),
    hour:       parseField(hourExpr,   ...FIELD_RANGES.hour),
    dayOfMonth: parseField(domExpr,    ...FIELD_RANGES.dayOfMonth),
    month:      parseField(monthExpr,  ...FIELD_RANGES.month),
    dayOfWeek:  parseField(dowExpr,    ...FIELD_RANGES.dayOfWeek),
  };
}

type Primitive = string | number | boolean | null | undefined;
