export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(value: number, min: number, max: number, context: string): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${context}"`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);

    let base: number[];
    if (rangePart === "*") {
      base = rangeArray(min, max);
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      base = rangeArray(
        clamp(lo, min, max, field),
        clamp(hi, min, max, field),
      );
    } else {
      const start = clamp(parseInt(rangePart, 10), min, max, field);
      base = rangeArray(start, max);
    }
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [loStr, hiStr] = segment.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max, field);
    const hi = clamp(parseInt(hiStr, 10), min, max, field);
    return rangeArray(lo, hi);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new TypeError(`Invalid value "${segment}" in field "${field}"`);
  return [clamp(num, min, max, field)];
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max, field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(exprs[i], min, max, field);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (result.dayOfWeek.includes(7)) {
    const normalized = new Set(result.dayOfWeek.map((v) => (v === 7 ? 0 : v)));
    result.dayOfWeek = Array.from(normalized).sort((a, b) => a - b);
  }

  return result;
}

