}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, fieldName: string): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), fieldName)) values.add(v);
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }
    let start = min;
    let end   = max;
    if (base !== "*") {
      if (base.includes("-")) {
        const [lo, hi] = base.split("-").map(n => parseInt(n, 10));
        start = clamp(lo, min, max);
        end   = clamp(hi, min, max);
        if (start > end) throw new RangeError(`Invalid range ${base} in field "${fieldName}"`);
      } else {
        start = clamp(parseInt(base, 10), min, max);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [loStr, hiStr] = expr.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max);
    const hi = clamp(parseInt(hiStr, 10), min, max);
    if (lo > hi) throw new RangeError(`Invalid range ${expr} in field "${fieldName}"`);
    return range(lo, hi);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Plain number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${expr}" in field "${fieldName}"`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronResult {
