      let from = min;
      let to = max;
      if (rangeStr !== "*") {
        if (rangeStr.includes("-")) {
          const [lo, hi] = rangeStr.split("-").map(Number);
          from = clamp(lo, min, max);
          to   = clamp(hi, min, max);
          if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
        } else {
          from = clamp(parseInt(rangeStr, 10), min, max);
        }
      }
      for (let v = from; v <= to; v += step) {
        values.add(v);
      }
      continue;
    }

    // Wildcard
    if (trimmed === "*") {
      for (const v of rangeArray(min, max)) values.add(v);
      continue;
    }

