type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step on wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step < 1) throw new Error(`Invalid step value in "${segment}" for ${field}`);
    return rangeArray(min, max, step);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [start, end] = rangePart.split("-").map(Number);
    const step = stepPart ? parseInt(stepPart, 10) : 1;
    if (start < min || end > max || start > end)
      throw new Error(`Range "${segment}" out of bounds for ${field} (${min}-${max})`);
    if (step < 1) throw new Error(`Invalid step value in "${segment}" for ${field}`);
    return rangeArray(start, end, step);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((s) => {
      const n = parseInt(s.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value "${s}" in list for ${field}`);
      return n;
    });
    const clamped = values.filter((n) => n >= min && n <= max);
    if (clamped.length !== values.length)
      throw new Error(`Some values in "${segment}" are out of bounds for ${field} (${min}-${max})`);
    return [...new Set(clamped)].sort((a, b) => a - b);
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    const n = parseInt(segment, 10);
    if (n < min || n > max)
      throw new Error(`Value ${n} out of bounds for ${field} (${min}-${max})`);
    return [n];
  }

  throw new Error(`Unrecognized cron segment "${segment}" for field ${field}`);
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return fields.reduce((acc, field, index) => {
    acc[field] = parseSegment(parts[index], field);
    return acc;
  }, {} as ParsedCron);
}

