      values = range(start, max);
    }

    return values.filter((v) => (v - values[0]) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const seen = new Set<number>();
    const result: number[] = [];
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        if (!seen.has(v)) {
          seen.add(v);
          result.push(v);
        }
      }
    }
    return result.sort((a, b) => a - b);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range: ${field}`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: ${field}`);
