  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list
  if (expr.includes(",")) {
    return expr.split(",").flatMap((part) => parseField(part.trim(), field));
  }

  // Wildcard with optional step: * or */n
  if (expr.startsWith("*")) {
    if (expr === "*") return rangeArray(min, max);
    if (expr.startsWith("*/")) {
      const step = parseInt(expr.slice(2), 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step in "${expr}" for field "${field}"`);
      return rangeArray(min, max, step);
    }
    throw new Error(`Invalid expression "${expr}" for field "${field}"`);
  }

  // Range: n-m or n-m/step
  if (expr.includes("-")) {
    const [rangePart, stepPart] = expr.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}" for field "${field}"`);
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end} for field "${field}"`);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step < 1) throw new Error(`Invalid step in "${expr}" for field "${field}"`);
    return rangeArray(start, end, step);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${expr}" for field "${field}"`);
  assertInRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields: (keyof CronFields)[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const values = parseField(exprs[i], field);
    result[field] = [...new Set(values)].sort((a, b) => a - b);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key as keyof typeof source];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }
    const [rangeMin, rangeMax] =
      rangePart === "*" ? [min, max] : parseRangeBounds(rangePart, min, max);
    return rangeArray(rangeMin, rangeMax, step);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [rangeMin, rangeMax] = parseRangeBounds(segment, min, max);
    return rangeArray(rangeMin, rangeMax);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron value: ${segment}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

function parseRangeBounds(
  range: string,
  min: number,
  max: number
): [number, number] {
  const parts = range.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range: ${range}`);
  }
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range bounds: ${range}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end}`);
  }
  if (start < min || end > max) {
    throw new Error(`Range ${range} out of bounds [${min}, ${max}]`);
  }
  return [start, end];
}

function parseField(expression: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max);
    for (const v of parsed) {
      // Normalize dayOfWeek: 7 is also Sunday (0)
      if (field === "dayOfWeek" && v === 7) {
        values.add(0);
      } else {
        values.add(clamp(v, min, max));
      }
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const fields = trimmed.split(" ");

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function validateRange(value: number, min: number, max: number, field: FieldName): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
  return value;
}

function expandFull(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseField(expr: string, field: FieldName): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return [...new Set(
      expr.split(",").flatMap((part) => parseField(part.trim(), field))
    )].sort((a, b) => a - b);
  }

  if (expr === "*") {
    return expandFull(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new SyntaxError(`Invalid step in "${expr}" for field "${field}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new SyntaxError(`Invalid step in "${expr}" for field "${field}"`);
    const [rangeMin, rangeMax] = rangePart.includes("-")
      ? rangePart.split("-").map((n) => validateRange(parseInt(n, 10), min, max, field))
      : [validateRange(parseInt(rangePart, 10), min, max, field), max];
    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = validateRange(parseInt(startStr, 10), min, max, field);
    const end = validateRange(parseInt(endStr, 10), min, max, field);
    if (start > end) throw new RangeError(`Invalid range "${expr}" for field "${field}": start > end`);
    return expandFull(start, end);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new SyntaxError(`Invalid token "${expr}" for field "${field}"`);
  validateRange(num, min, max, field);
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}`);
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronExpression;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(from: number, to: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step with wildcard: */n
  const stepWildcard = segment.match(/^\*\/(\d+)$/);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step < 1) throw new Error(`Step must be >= 1 in field "${field}"`);
    return rangeArray(min, max, step);
  }

  // Range with optional step: a-b or a-b/n
  const rangeStep = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeStep) {
    const from = parseInt(rangeStep[1], 10);
    const to   = parseInt(rangeStep[2], 10);
    const step = rangeStep[3] !== undefined ? parseInt(rangeStep[3], 10) : 1;
    validateRange(from, min, max, field);
    validateRange(to,   min, max, field);
    if (from > to) throw new Error(`Range start ${from} > end ${to} in field "${field}"`);
    if (step < 1)  throw new Error(`Step must be >= 1 in field "${field}"`);
    return rangeArray(from, to, step);
  }

  // Plain number
  const plain = segment.match(/^(\d+)$/);
  if (plain) {
    const value = parseInt(plain[1], 10);
    validateRange(value, min, max, field);
    return [value];
  }

  throw new Error(`Invalid segment "${segment}" in field "${field}"`);
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) throw new Error(`Empty field "${field}"`);

  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), field)) {
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  min: number;
  max: number;
}

const FIELD_SPECS: Record<keyof CronResult, FieldSpec> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(from: number, to: number, step = 1): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, spec: FieldSpec): number[] {
  const { min, max } = spec;

  // Wildcard with optional step: * or */n
  if (segment === "*") return rangeArray(min, max);

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step: ${segment}`);
    return rangeArray(min, max, step);
  }

  // Comma-separated list: recurse on each part
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .flatMap((part) => parseSegment(part.trim(), spec));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    const step  = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step) || step < 1)
      throw new RangeError(`Invalid range expression: ${segment}`);
    if (start < min || end > max)
      throw new RangeError(`Range ${start}-${end} out of bounds [${min}-${max}]`);

    return rangeArray(start, end, step);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new TypeError(`Invalid field value: ${segment}`);
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of bounds [${min}-${max}]`);

  return [value];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_SPECS) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return keys.reduce((acc, key, i) => {
    acc[key] = parseSegment(exprs[i], FIELD_SPECS[key]);
    return acc;
  }, {} as CronResult);
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const validate = (n: number): number => {
    if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
    return n;
  };

  const parseSingle = (token: string): number[] => {
    if (token === "*") return range(min, max);

    if (token.includes("/")) {
      const [base, stepStr] = token.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

      let start = min;
      let end = max;

      if (base !== "*") {
        if (base.includes("-")) {
          const [rangeStart, rangeEnd] = base.split("-").map(Number);
          start = validate(rangeStart);
          end = validate(rangeEnd);
          if (start > end) throw new Error(`Invalid range: ${base}`);
        } else {
          start = validate(parseInt(base, 10));
        }
      }

      const result: number[] = [];
      for (let i = start; i <= end; i += step) result.push(i);
      return result;
    }

    if (token.includes("-")) {
      const [startStr, endStr] = token.split("-");
      const start = validate(parseInt(startStr, 10));
      const end = validate(parseInt(endStr, 10));
      if (start > end) throw new Error(`Invalid range: ${token}`);
      return range(start, end);
    }

    const n = parseInt(token, 10);
    if (isNaN(n)) throw new Error(`Invalid cron token: ${token}`);
    return [validate(n)];
  };

  const values = expr
    .split(",")
    .flatMap(parseSingle);

  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;

  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(exprs[i], min, max);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (result.dayOfWeek.includes(7) && !result.dayOfWeek.includes(0)) {
    result.dayOfWeek = [0, ...result.dayOfWeek.filter(d => d !== 7)].sort((a, b) => a - b);
  } else if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = result.dayOfWeek.filter(d => d !== 7);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key as keyof typeof source];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends Record<string, unknown>, S extends Record<string, unknown>>(
  target: T,
  source: S
): T & S {
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let i = min; i <= max; i += step) results.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepStr] = part.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [startStr, endStr] = rangePart.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end = endStr !== undefined ? clamp(parseInt(endStr, 10), min, max) : max;
      for (let i = start; i <= end; i += step) results.add(i);
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end = clamp(parseInt(endStr, 10), min, max);
      if (start > end) throw new RangeError(`Invalid range: ${part}`);
      for (let i = start; i <= end; i++) results.add(i);
    } else {
      const value = parseInt(part, 10);
      if (isNaN(value)) throw new Error(`Invalid cron value: ${part}`);
      results.add(clamp(value, min, max));
    }
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard
  if (expr === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expr}" for field "${fieldName}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      rangeMin = parseInt(startStr, 10);
      rangeMax = parseInt(endStr, 10);
    } else {
      rangeMin = parseInt(rangePart, 10);
      rangeMax = max;
    }

    if (
      isNaN(rangeMin) ||
      isNaN(rangeMax) ||
      rangeMin < min ||
      rangeMax > max ||
      rangeMin > rangeMax
    ) {
      throw new Error(`Invalid range in "${expr}" for field "${fieldName}" (valid: ${min}-${max})`);
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end) || start < min || end > max || start > end) {
      throw new Error(`Invalid range "${expr}" for field "${fieldName}" (valid: ${min}-${max})`);
    }

    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value) || value < min || value > max) {
    throw new Error(`Value ${expr} out of range for field "${fieldName}" (valid: ${min}-${max})`);
  }

  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(
  target: Record<string, unknown>,
  source: Record<string, unknown>
): Record<string, unknown> {
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in "${expr}"`);
    }
    let rangeMin = min;
    let rangeMax = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        rangeMin = clamp(lo, min, max);
        rangeMax = clamp(hi, min, max);
        if (rangeMin > rangeMax) throw new Error(`Invalid range in "${expr}"`);
      } else {
        rangeMin = clamp(parseInt(rangePart, 10), min, max);
      }
    }
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    const rangeMin = clamp(lo, min, max);
    const rangeMax = clamp(hi, min, max);
    if (rangeMin > rangeMax) throw new Error(`Invalid range "${expr}" for field ${field}`);
    return rangeArray(rangeMin, rangeMax);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${expr}" for field ${field}`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;
